SELECT licence_area
FROM multiplexes
WHERE status = 'active';

SELECT COUNT(station_id) AS active_stations
FROM station_multiplex_mapping
WHERE end_date IS NULL;

SELECT AVG(frequency) AS average_frequency
FROM multiplexes
WHERE region = 'North East' AND status = 'active';

SELECT AVG(duration) AS average_music_duration
FROM station_content
WHERE program_type = 'Music';
